fn solve(piles: Vec<i64>) -> i64 {
    let mut piles = piles;
    piles.sort();
    let n = piles.len();
    let mut total = 0;
    let mut heap = std::collections::BinaryHeap::new();

    for i in 0..n.step_by(3) {
        heap.push(piles[i + 1]);
    }

    while let Some(val) = heap.pop() {
        total += val;
    }

    total
}
